export const AUDIENCES = ["client", "junior", "reviewer", "self", "future-self"];
export function normalizeAudience(raw) {
    const a = (raw ?? "reviewer").toLowerCase().replace(/_/g, "-");
    if (a === "future-self" || a === "futureself" || a === "self")
        return a === "self" ? "self" : "future-self";
    if (a === "client" || a === "junior" || a === "reviewer")
        return a;
    return "reviewer";
}
const audienceGuide = {
    client: "Write for a non-IDE stakeholder (agency client or PM). Avoid jargon; explain outcomes, risks, what changed in product terms, and how to verify. Assume they will not open the IDE.",
    junior: "Write for a junior engineer inheriting this work. Explain architecture choices, where to look first, pitfalls, and how to extend safely. Link concepts to concrete files.",
    reviewer: "Write for a senior code reviewer. Focus on intent, risk hotspots, test gaps, migration notes, and what must be verified before merge. Be precise and skeptical.",
    self: "Write for the author later today. Capture intent, unfinished threads, and the next 3 concrete actions.",
    "future-self": "Write for the author in 3 months. Capture why decisions were made, invariants, landmines, and how to re-enter the mental model fast.",
};
export function systemPrompt(kind, audience) {
    const role = kind === "pr"
        ? "You write PR walkthrough narratives that travel with the pull request."
        : kind === "explain"
            ? "You write durable code-explain artifacts (not chat). Output is a file people commit or share."
            : "You write portable handoff packets for work that must leave one person's head and one IDE.";
    return [
        `You are DevFlow, a git-native shipping-artifact writer.`,
        role,
        `Audience mode: ${audience}. ${audienceGuide[audience]}`,
        ``,
        `Hard rules:`,
        `- Output ONLY markdown suitable to save as a .md file. No chat preamble.`,
        `- Durable artifact > interactive Q&A. Someone must trust this with Cursor closed.`,
        `- Prefer concrete paths, symbols, commands, and verification steps.`,
        `- If context is thin, say what is unknown instead of inventing.`,
        `- Do not dump entire files; cite paths and summarize with surgical quotes when needed.`,
        `- Keep total length practical: ~400â€“900 words unless complexity demands more.`,
        ``,
        `Required sections (use these headings):`,
        kind === "pr"
            ? [
                `## PR title suggestion`,
                `## Summary`,
                `## Motivation`,
                `## What changed`,
                `## Risk & review focus`,
                `## Test plan`,
                `## Rollout / follow-ups`,
            ].join("\n")
            : [
                `## Title`,
                `## TL;DR`,
                `## Context`,
                `## What shipped / changed`,
                `## How it works (map)`,
                `## Risks & landmines`,
                `## How to verify`,
                `## Handoff checklist`,
                `## Open questions`,
            ].join("\n"),
    ].join("\n");
}
export function userPrompt(kind, audience, contextMarkdown, extra) {
    const goal = kind === "pr"
        ? "Produce a PR walkthrough markdown artifact from the git context below."
        : kind === "explain"
            ? "Produce an explain/walkthrough markdown artifact from the git context below."
            : "Produce a handoff packet markdown artifact from the git context below.";
    return [
        goal,
        `Audience: ${audience}`,
        extra ? `Extra instructions from user:\n${extra}` : "",
        ``,
        `--- GIT CONTEXT ---`,
        contextMarkdown,
        `--- END CONTEXT ---`,
    ]
        .filter(Boolean)
        .join("\n");
}
/** Offline fallback when no API key â€” still produces a useful skeleton from git. */
export function offlineArtifact(kind, audience, meta) {
    const title = kind === "pr"
        ? `PR walkthrough: ${meta.branch} @ ${meta.head}`
        : `Handoff: ${meta.repo} (${meta.branch} @ ${meta.head})`;
    const files = meta.changedFiles.length
        ? meta.changedFiles.map((f) => `- \`${f}\``).join("\n")
        : "- (no changed files detected)";
    if (kind === "pr") {
        return [
            `## PR title suggestion`,
            `${meta.branch}: shipping updates @ ${meta.head}`,
            ``,
            `## Summary`,
            `Offline skeleton generated by DevFlow (no API key). Fill intent after review.`,
            `Audience: **${audience}**. Range: \`${meta.rangeLabel}\`.`,
            ``,
            `## Motivation`,
            `_TODO: why this change exists_`,
            ``,
            `## What changed`,
            files,
            ``,
            "```",
            meta.diffStat,
            "```",
            ``,
            `## Risk & review focus`,
            `- Review diff stat and changed paths above`,
            `- Confirm tests cover new branches`,
            ``,
            `## Test plan`,
            `- [ ] Install / build succeeds`,
            `- [ ] Smoke the happy path`,
            `- [ ] Check edge cases listed in Open questions`,
            ``,
            `## Rollout / follow-ups`,
            `- [ ] Merge when review checklist green`,
            ``,
            `## Git log`,
            "```",
            meta.log,
            "```",
            ``,
            `---`,
            `*Generated by DevFlow offline mode. Set ANTHROPIC_API_KEY for full narrative.*`,
        ].join("\n");
    }
    return [
        `## Title`,
        title,
        ``,
        `## TL;DR`,
        `Offline handoff skeleton for **${meta.repo}** on \`${meta.branch}\` (${meta.head}).`,
        `Audience: **${audience}**. Set \`ANTHROPIC_API_KEY\` (BYOK) for a full AI walkthrough.`,
        ``,
        `## Context`,
        `- Range: \`${meta.rangeLabel}\``,
        `- Status:`,
        "```",
        meta.status,
        "```",
        ``,
        `## What shipped / changed`,
        files,
        ``,
        `### Diff stat`,
        "```",
        meta.diffStat,
        "```",
        ``,
        `### Recent commits`,
        "```",
        meta.log,
        "```",
        ``,
        `## How it works (map)`,
        `_TODO: map entrypoints and data flow once AI pass runs or author fills in._`,
        ``,
        `## Risks & landmines`,
        `- Context was collected without model synthesis â€” verify claims against code.`,
        ``,
        `## How to verify`,
        `- [ ] Read changed files list`,
        `- [ ] Run project tests / typecheck`,
        `- [ ] Exercise the primary user path`,
        ``,
        `## Handoff checklist`,
        `- [ ] Artifact reviewed by author`,
        `- [ ] Shared with next human (PR comment, client email, or commit under docs/)`,
        `- [ ] Open questions answered or ticketed`,
        ``,
        `## Open questions`,
        `- What should the next human do first?`,
        `- Any migrations / env vars / secrets required?`,
        ``,
        `---`,
        `*Generated by DevFlow offline mode. BYOK: export ANTHROPIC_API_KEY=sk-... then re-run.*`,
    ].join("\n");
}
